previewCss:
.darma-loader-darma-custom-005 {
  width: 40px;
  aspect-ratio: 1;
  border-radius: 50%;
  background: radial-gradient(farthest-side, var(--loader-color, #ED303C) 94%, #0000), radial-gradient(farthest-side, #3B8183 94%, #0000), radial-gradient(farthest-side, #FAD089 94%, #0000), radial-gradient(farthest-side, var(--loader-secondary-color, #FF9C5B) 94%, #0000), var(--loader-color, #ED303C);
  background-size: 105% 105%;
  background-repeat: no-repeat;
  animation: darma-loader-darma-custom-005-l5 2s infinite;
}
@keyframes darma-loader-darma-custom-005-l5 {
  0% { background-position: 50% -50px, -40px 50%, 50% calc(100% + 50px), calc(100% + 50px) 50%; }
  20%, 25% { background-position: 50% -50px, -50px 50%, 50% calc(100% + 50px), 50% 50%; }
  45%, 50% { background-position: 50% -50px, -50px 50%, 50% 50%, 50% 50%; }
  75% { background-position: 50% -50px, 50% 50%, 50% 50%, 50% 50%; }
  95%, 100% { background-position: 50% 50%, 50% 50%, 50% 50%, 50% 50%; }
}

